mapper.select:
SELECT oo.*, operator.login_name AS operator_name, auditor.login_name AS auditor_name FROM outbound_order oo LEFT JOIN sys_user operator ON oo.operator_id = operator.id AND operator.is_deleted = 0 LEFT JOIN sys_user auditor ON oo.auditor_id = auditor.id AND auditor.is_deleted = 0 WHERE oo.is_deleted = 0
AND oo.receiver_name LIKE CONCAT('%', #{receiverName}, '%')
AND oo.audit_status = #{auditStatus}
AND oo.outbound_time >= #{outboundTimeStart}
AND oo.outbound_time <= #{outboundTimeEnd}
ORDER BY oo.outbound_time DESC
